<script setup lang="ts">
import type { Connection, ConnectionInput } from '~/types/database'
const props = defineProps<{ modelValue: boolean; connection?: Connection }>()
const emit = defineEmits<{ 'update:modelValue': [value: boolean]; saved: []; deleted: [] }>()
const api = useApi(); const form = reactive<ConnectionInput>({ name: '', driver: 'mysql', host: 'localhost', port: 3306, username: 'root', password: '', initialDatabase: '', color: '#3B82F6', environment: 'development', sslEnabled: false, timeoutSeconds: 30 }); const testing = ref(false); const saving = ref(false); const deleting = ref(false); const confirmDelete = ref(false)
const { t } = useI18n()
const { error: notifyError, success: notifySuccess } = useToast()
const connectionColors = ['#3B82F6', '#10B981', '#F59E0B', '#F97316', '#EF4444', '#8B5CF6']
function resetForm(connection?: Connection) { Object.assign(form, { name: connection?.name ?? '', driver: connection?.driver ?? 'mysql', host: connection?.host ?? 'localhost', port: connection?.port ?? 3306, username: connection?.username ?? 'root', password: '', initialDatabase: connection?.initialDatabase ?? '', color: connection?.color ?? '#3B82F6', environment: connection?.environment ?? 'development', sslEnabled: connection?.sslEnabled ?? false, timeoutSeconds: connection?.timeoutSeconds ?? 30 }) }
watch(() => [props.modelValue, props.connection] as const, () => { if (props.modelValue) resetForm(props.connection) }, { immediate: true })
function payload() { return { name: form.name, driver: form.driver, host: form.host, port: form.port, username: form.username, password: form.password || undefined, initialDatabase: form.initialDatabase, color: form.color, environment: form.environment, sslEnabled: form.sslEnabled, timeoutSeconds: form.timeoutSeconds } }
async function test() { testing.value=true; try { await api('/connections/test', { method: 'POST', body: payload() }); notifySuccess(t('connection.succeeded')) } catch (e:any) { notifyError(e.message) } finally { testing.value=false } }
async function save() { saving.value=true; try { if (props.connection) await api(`/connections/${props.connection.id}`, { method:'PUT', body:payload() }); else await api('/connections', { method:'POST', body:payload() }); emit('saved'); emit('update:modelValue',false); notifySuccess(t('common.save')) } catch(e:any) { notifyError(e.message) } finally { saving.value=false } }
function requestRemove() { if (props.connection) confirmDelete.value = true }
async function remove() { if (!props.connection) return; confirmDelete.value=false; deleting.value=true; try { await api(`/connections/${props.connection.id}`, { method:'DELETE' }); emit('deleted'); emit('update:modelValue',false); notifySuccess(t('connection.delete')) } catch(e:any) { notifyError(e.message) } finally { deleting.value=false } }
</script>
<template><Teleport to="body"><div v-if="modelValue" class="fixed inset-0 z-50 grid place-items-center bg-slate-950/40 p-4" @mousedown.self="$emit('update:modelValue', false)"><form class="w-full max-w-xl rounded-xl border border-line bg-panel p-5 shadow-panel" @submit.prevent="save"><div class="mb-5 flex items-center justify-between"><div><h2 class="font-semibold">{{ connection ? t('connection.edit') : t('connection.new') }}</h2><p class="mt-1 text-sm text-muted">{{ t('connection.passwordEncrypted') }}</p></div><button type="button" class="grid rounded p-1 text-muted hover:bg-canvas" :aria-label="t('common.close')" @click="$emit('update:modelValue',false)"><Icon name="lucide:x" class="h-4 w-4" aria-hidden="true" /></button></div><div class="grid gap-3 sm:grid-cols-2"><label class="field sm:col-span-2">{{ t('connection.name') }}<input v-model="form.name" required :placeholder="t('connection.namePlaceholder')" ></label><label class="field sm:col-span-2">{{ t('connection.environment') }}<div class="grid grid-cols-2 gap-2"><label class="environment-option" :class="form.environment === 'development' ? 'environment-option-active' : ''"><input v-model="form.environment" value="development" type="radio" ><span><b>{{ t('connection.development') }}</b><small>{{ t('connection.developmentDescription') }}</small></span></label><label class="environment-option" :class="form.environment === 'production' ? 'environment-option-active' : ''"><input v-model="form.environment" value="production" type="radio" ><span><b>{{ t('connection.production') }}</b><small>{{ t('connection.productionDescription') }}</small></span></label></div></label><label class="field">{{ t('connection.host') }}<input v-model="form.host" required ></label><label class="field">{{ t('connection.port') }}<input v-model.number="form.port" required type="number" min="1" max="65535" ></label><label class="field">{{ t('connection.username') }}<input v-model="form.username" required ></label><label class="field">{{ t('connection.password') }}<input v-model="form.password" :required="!connection" type="password" :placeholder="connection ? t('connection.keepPassword') : ''" ></label><label class="field sm:col-span-2">{{ t('connection.initialDatabase') }} <span class="font-normal text-muted">{{ t('ai.optional') }}</span><input v-model="form.initialDatabase" ></label><div class="field"><span>{{ t('connection.connectionColor') }}</span><div class="color-picker" role="group" :aria-label="t('connection.connectionColor')"><button v-for="color in connectionColors" :key="color" type="button" class="color-swatch" :class="form.color === color ? 'color-swatch-active' : ''" :style="{ backgroundColor: color }" :aria-label="color" :aria-pressed="form.color === color" @click="form.color = color"><Icon v-if="form.color === color" name="lucide:check" class="h-3.5 w-3.5" aria-hidden="true" /></button><label class="color-custom-picker" :style="{ backgroundColor: form.color }" :title="form.color"><input v-model="form.color" type="color" :aria-label="t('connection.connectionColor')" ></label></div></div><label class="field">{{ t('connection.timeout') }}<input v-model.number="form.timeoutSeconds" type="number" min="1" max="300" ></label><label class="mt-6 flex items-center gap-2 text-sm"><input v-model="form.sslEnabled" type="checkbox" > {{ t('connection.useSsl') }}</label></div><div class="mt-5 flex items-center justify-between gap-2"><button v-if="connection" type="button" class="rounded-md px-3 py-2 text-sm text-rose-500 hover:bg-rose-500/10 disabled:opacity-60" :disabled="deleting" @click="requestRemove">{{ deleting ? t('connection.deleting') : t('connection.delete') }}</button><span v-else /><div class="flex gap-2"><button type="button" class="rounded-md px-3 py-2 text-sm hover:bg-canvas" @click="$emit('update:modelValue',false)">{{ t('connection.cancel') }}</button><button type="button" class="rounded-md border border-line px-3 py-2 text-sm hover:bg-canvas disabled:opacity-60" :disabled="testing || !form.password" @click="test">{{ testing ? t('connection.testing') : t('connection.test') }}</button><button class="rounded-md bg-accent px-3 py-2 text-sm font-medium text-white disabled:opacity-60" :disabled="saving || deleting">{{ saving ? t('connection.saving') : t('connection.save') }}</button></div></div></form></div></Teleport><AppConfirmDialog v-model="confirmDelete" :title="t('connection.deleteTitle')" :description="t('connection.deleteConfirm', { name: connection?.name || '' })" :confirm-label="t('connection.deleteAction')" :cancel-label="t('connection.cancel')" tone="danger" @confirm="remove" /></template>
<style scoped>.field { @apply grid gap-1 text-sm font-medium; }.field input { @apply h-9 rounded-md border border-line bg-canvas px-2.5 font-normal text-ink focus:outline-none focus:ring-2 focus:ring-accent/50; }.environment-option { @apply flex cursor-pointer gap-2 rounded-md border border-line bg-canvas p-2 font-normal; }.environment-option input { @apply mt-1 h-auto; }.environment-option span { @apply grid gap-0.5; }.environment-option small { @apply text-xs text-muted; }.environment-option-active { @apply border-accent bg-accent/5; }.color-picker { @apply flex h-9 items-center gap-1.5; }.color-swatch { @apply grid h-7 w-7 shrink-0 place-items-center rounded-full border-2 border-transparent text-xs text-white shadow-sm transition-transform hover:scale-110 focus:outline-none focus:ring-2 focus:ring-accent/50; }.color-swatch-active { @apply border-ink/70 ring-2 ring-canvas; }.color-custom-picker { @apply relative grid h-7 w-7 shrink-0 cursor-pointer overflow-hidden rounded-full border-2 border-dashed border-line transition-colors hover:border-muted focus-within:ring-2 focus-within:ring-accent/50; }.color-custom-picker input { @apply absolute inset-0 h-full w-full cursor-pointer opacity-0; }</style>
